// Solution
#include <iostream>
#include <vector>

using namespace std;

void bubbleSort(vector<int>& nums) {
    bool swapped = true;
    while (swapped) {
        swapped = false;
        for (int i = 0; i < nums.size() - 1; i++) {
            if (nums[i] > nums[i + 1]) {
                int temp = nums[i];
                nums[i] = nums[i + 1];
                nums[i + 1] = temp;
                swapped = true;
            }
        }
    }
}

int main() {
    vector<int> nums = {5, 3, 8, 1, 2};
    bubbleSort(nums);
    for (auto num : nums) {
        cout << num << ' ';n}
    return 0;
}

