// Solution
import sys

def bubbleSort(nums):
    swapped = True
    while swapped:
        swapped = False
        for i in range(len(nums) - 1):
            if nums[i] > nums[i + 1]:
                nums[i], nums[i + 1] = nums[i + 1], nums[i]
                swapped = True
    return nums

if __name__ == '__main__':
    nums = [5, 3, 8, 1, 2]
    bubbleSort(nums)
    print(*nums)

